const express = require('express');

const app = express();
app.use(express.json({ limit: '1mb' }));

// --- In-memory store (replace with DB in production) ---
const db = {
  players: new Map(), // playerId -> { levels: Map(levelId -> completion), pendingRewards: Map(rewardId -> reward) }
};

function nowMs() {
  return Date.now();
}

function getPlayer(playerId) {
  if (!db.players.has(playerId)) {
    db.players.set(playerId, {
      levels: new Map(),
      pendingRewards: new Map(),
      createdAt: nowMs(),
      updatedAt: nowMs(),
    });
  }
  return db.players.get(playerId);
}

function parseIntSafe(v) {
  const n = Number(v);
  return Number.isFinite(n) ? Math.trunc(n) : NaN;
}

function parseNumSafe(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : NaN;
}

function requireString(v) {
  return typeof v === 'string' && v.trim().length > 0 ? v.trim() : null;
}

function clamp(n, min, max) {
  return Math.max(min, Math.min(max, n));
}

function makeId(prefix = 'r') {
  return `${prefix}_${nowMs().toString(36)}_${Math.random().toString(36).slice(2, 10)}`;
}

// --- Reward logic (client-reported metrics; tune as needed) ---
function computeRewardsForCompletion({ levelId, score, timeMs, attempt }) {
  // Basic anti-abuse clamps while still "based on client metrics"
  const s = clamp(score, 0, 10_000_000);
  const t = clamp(timeMs, 1, 24 * 60 * 60 * 1000);

  const rewards = [];

  // Base coins for completion
  const baseCoins = clamp(Math.floor(50 + s / 200), 50, 10_000);
  rewards.push({
    type: 'coins',
    amount: baseCoins,
    reason: 'level_complete_base',
    meta: { levelId },
  });

  // Score bonus tiers
  if (s >= 5000) rewards.push({ type: 'gems', amount: 2, reason: 'score_tier_5000', meta: { levelId } });
  if (s >= 15000) rewards.push({ type: 'gems', amount: 3, reason: 'score_tier_15000', meta: { levelId } });
  if (s >= 50000) rewards.push({ type: 'gems', amount: 5, reason: 'score_tier_50000', meta: { levelId } });

  // Speed bonus tiers (lower time is better)
  if (t <= 60_000) rewards.push({ type: 'coins', amount: 200, reason: 'speed_under_60s', meta: { levelId } });
  if (t <= 30_000) rewards.push({ type: 'coins', amount: 350, reason: 'speed_under_30s', meta: { levelId } });
  if (t <= 15_000) rewards.push({ type: 'gems', amount: 2, reason: 'speed_under_15s', meta: { levelId } });

  // First-attempt bonus (client-reported attempt count)
  if (attempt === 1) rewards.push({ type: 'gems', amount: 1, reason: 'first_attempt', meta: { levelId } });

  // Cap total gem rewards per completion to avoid runaway
  let gemTotal = 0;
  for (const r of rewards) if (r.type === 'gems') gemTotal += r.amount;
  if (gemTotal > 10) {
    const over = gemTotal - 10;
    for (let i = rewards.length - 1; i >= 0 && over > 0; i--) {
      const r = rewards[i];
      if (r.type !== 'gems') continue;
      const reduce = Math.min(r.amount, over);
      r.amount -= reduce;
      gemTotal -= reduce;
      if (r.amount === 0) rewards.splice(i, 1);
    }
  }

  return rewards.filter(r => r.amount > 0);
}

function validateCompletionBody(body) {
  const playerId = requireString(body.playerId);
  const levelId = requireString(body.levelId);

  const score = parseIntSafe(body.score);
  const timeMs = parseIntSafe(body.timeMs);

  const attempt = body.attempt == null ? 1 : parseIntSafe(body.attempt);

  const clientTs = body.clientTs == null ? null : parseIntSafe(body.clientTs);

  if (!playerId) return { ok: false, error: 'playerId required' };
  if (!levelId) return { ok: false, error: 'levelId required' };
  if (!Number.isFinite(score) || score < 0) return { ok: false, error: 'score must be a non-negative number' };
  if (!Number.isFinite(timeMs) || timeMs <= 0) return { ok: false, error: 'timeMs must be a positive number' };
  if (!Number.isFinite(attempt) || attempt <= 0 || attempt > 9999) return { ok: false, error: 'attempt must be a positive number' };
  if (clientTs !== null && (!Number.isFinite(clientTs) || clientTs <= 0)) return { ok: false, error: 'clientTs must be a positive number if provided' };

  const meta = body.meta && typeof body.meta === 'object' ? body.meta : undefined;

  return { ok: true, value: { playerId, levelId, score, timeMs, attempt, clientTs, meta } };
}

// --- Endpoints ---

app.get('/health', (req, res) => {
  res.json({ ok: true, time: new Date().toISOString() });
});

app.post('/v1/levels/complete', (req, res) => {
  const v = validateCompletionBody(req.body);
  if (!v.ok) return res.status(400).json({ ok: false, error: v.error });

  const { playerId, levelId, score, timeMs, attempt, clientTs, meta } = v.value;

  const player = getPlayer(playerId);
  const existing = player.levels.get(levelId);

  const completionId = makeId('c');
  const serverTs = nowMs();

  // Record best metrics for level
  let isNewBest = false;
  let bestScore = score;
  let bestTimeMs = timeMs;

  if (existing) {
    bestScore = Math.max(existing.bestScore, score);
    bestTimeMs = Math.min(existing.bestTimeMs, timeMs);
    isNewBest = bestScore !== existing.bestScore || bestTimeMs !== existing.bestTimeMs;
  } else {
    isNewBest = true;
  }

  const completionRecord = {
    levelId,
    lastCompletion: { completionId, score, timeMs, attempt, clientTs, serverTs, meta },
    bestScore,
    bestTimeMs,
    completedCount: existing ? existing.completedCount + 1 : 1,
    firstCompletedAt: existing ? existing.firstCompletedAt : serverTs,
    updatedAt: serverTs,
  };
  player.levels.set(levelId, completionRecord);
  player.updatedAt = serverTs;

  // Award rewards based on client-reported metrics for this completion
  const rewardItems = computeRewardsForCompletion({ levelId, score, timeMs, attempt });

  const rewardId = makeId('reward');
  const reward = {
    rewardId,
    playerId,
    levelId,
    status: 'pending',
    createdAt: serverTs,
    source: {
      type: 'level_complete',
      completionId,
      score,
      timeMs,
      attempt,
      clientTs,
      serverTs,
    },
    items: rewardItems,
  };

  // Prevent duplicate rewards for identical completionId (should be unique anyway)
  player.pendingRewards.set(rewardId, reward);

  return res.status(200).json({
    ok: true,
    completion: {
      completionId,
      playerId,
      levelId,
      received: { score, timeMs, attempt, clientTs },
      serverTs,
      isNewBest,
      best: { score: bestScore, timeMs: bestTimeMs },
      completedCount: completionRecord.completedCount,
    },
    reward: {
      rewardId,
      status: reward.status,
      items: reward.items,
    },
  });
});

app.get('/v1/rewards/pending', (req, res) => {
  const playerId = requireString(req.query.playerId);
  if (!playerId) return res.status(400).json({ ok: false, error: 'playerId required' });

  const player = getPlayer(playerId);
  const pending = Array.from(player.pendingRewards.values()).filter(r => r.status === 'pending');

  res.json({ ok: true, playerId, pending });
});

app.post('/v1/rewards/claim', (req, res) => {
  const playerId = requireString(req.body.playerId);
  const rewardId = requireString(req.body.rewardId);

  if (!playerId) return res.status(400).json({ ok: false, error: 'playerId required' });
  if (!rewardId) return res.status(400).json({ ok: false, error: 'rewardId required' });

  const player = getPlayer(playerId);
  const reward = player.pendingRewards.get(rewardId);

  if (!reward) return res.status(404).json({ ok: false, error: 'reward not found' });
  if (reward.playerId !== playerId) return res.status(403).json({ ok: false, error: 'reward does not belong to player' });

  if (reward.status === 'claimed') {
    return res.status(200).json({
      ok: true,
      rewardId,
      status: reward.status,
      claimedAt: reward.claimedAt,
      items: reward.items,
    });
  }

  reward.status = 'claimed';
  reward.claimedAt = nowMs();
  player.updatedAt = reward.claimedAt;

  res.status(200).json({
    ok: true,
    rewardId,
    status: reward.status,
    claimedAt: reward.claimedAt,
    items: reward.items,
  });
});

app.get('/v1/players/:playerId/progress', (req, res) => {
  const playerId = requireString(req.params.playerId);
  if (!playerId) return res.status(400).json({ ok: false, error: 'playerId required' });

  const player = getPlayer(playerId);
  const levels = {};
  for (const [levelId, rec] of player.levels.entries()) {
    levels[levelId] = {
      bestScore: rec.bestScore,
      bestTimeMs: rec.bestTimeMs,
      completedCount: rec.completedCount,
      firstCompletedAt: rec.firstCompletedAt,
      updatedAt: rec.updatedAt,
      lastCompletion: rec.lastCompletion,
    };
  }

  res.json({
    ok: true,
    playerId,
    levels,
    pendingRewardsCount: Array.from(player.pendingRewards.values()).filter(r => r.status === 'pending').length,
    updatedAt: player.updatedAt,
  });
});

